mapper.select:
SELECT id, payment_no, order_no, biz_type, user_id, payment_amount, payment_status, payment_channel, payment_method, payment_time, payment_expire_time, third_payment_no, third_transaction_no, attach_data, notify_url, return_url, client_ip, device_info, subject, body, currency, error_code, error_message, notify_status, notify_count, last_notify_time, next_notify_time, is_deleted, create_by, update_by, create_time, update_time, version FROM pay_order
AND payment_no LIKE CONCAT(#{queryParams.paymentNo}, '%')
AND order_no LIKE CONCAT(#{queryParams.orderNo}, '%')
AND biz_type LIKE CONCAT(#{queryParams.bizType}, '%')
AND user_id LIKE CONCAT(#{queryParams.userId}, '%')
AND payment_status LIKE CONCAT(#{queryParams.paymentStatus}, '%')
AND payment_channel LIKE CONCAT(#{queryParams.paymentChannel}, '%')
AND payment_time >= #{startDate}
AND payment_time <= #{endDate}
AND third_payment_no LIKE CONCAT(#{queryParams.thirdPaymentNo}, '%')
AND create_time >= #{startDate}
AND create_time <= #{endDate}

SELECT *
FROM pay_order
WHERE payment_status IN (0, 10)
  AND create_time >= #{maxCreatedAt}
  AND create_time <= #{lastCreatedAt}
  AND id < #{lastId}
ORDER BY create_time DESC, id DESC
    LIMIT #{limit}
